// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract SecureChain {
    enum ClaimStatus { PENDING, APPROVED, REJECTED }

    struct Policy {
        string policyId;
        address user;
        uint256 coverageAmount;
        bool active;
        uint256 timestamp;
    }

    struct Claim {
        string claimId;
        string policyId;
        address user;
        uint256 amount;
        ClaimStatus status;
        string reason; // For rejection or specific notes
        uint256 timestamp;
    }

    address public admin;
    mapping(string => Policy) public policies;
    mapping(string => Claim) public claims;
    string[] public policyIds;
    string[] public claimIds;

    event PolicyRecorded(string policyId, address user, uint256 amount);
    event ClaimSubmitted(string claimId, string policyId, address user, uint256 amount);
    event ClaimProcessed(string claimId, ClaimStatus status);

    modifier onlyAdmin() {
        require(msg.sender == admin, "Only admin can perform this action");
        _;
    }

    constructor() {
        admin = msg.sender;
    }

    function recordPolicy(string memory _policyId, address _user, uint256 _amount) public onlyAdmin {
        require(policies[_policyId].user == address(0), "Policy already exists");

        policies[_policyId] = Policy({
            policyId: _policyId,
            user: _user,
            coverageAmount: _amount,
            active: true,
            timestamp: block.timestamp
        });

        policyIds.push(_policyId);
        emit PolicyRecorded(_policyId, _user, _amount);
    }

    function submitClaim(string memory _claimId, string memory _policyId, uint256 _amount) public {
        require(policies[_policyId].user == msg.sender, "User does not own this policy");
        require(claims[_claimId].user == address(0), "Claim already exists");

        claims[_claimId] = Claim({
            claimId: _claimId,
            policyId: _policyId,
            user: msg.sender,
            amount: _amount,
            status: ClaimStatus.PENDING,
            reason: "",
            timestamp: block.timestamp
        });

        claimIds.push(_claimId);
        emit ClaimSubmitted(_claimId, _policyId, msg.sender, _amount);
    }

    function processClaim(string memory _claimId, ClaimStatus _status, string memory _reason) public onlyAdmin {
        require(claims[_claimId].user != address(0), "Claim does not exist");
        require(claims[_claimId].status == ClaimStatus.PENDING, "Claim already processed");

        claims[_claimId].status = _status;
        claims[_claimId].reason = _reason;

        emit ClaimProcessed(_claimId, _status);
    }

    function getPolicyCount() public view returns (uint256) {
        return policyIds.length;
    }

    function getClaimCount() public view returns (uint256) {
        return claimIds.length;
    }
}
